const solve = (points, target) => {
    // Helper function to serialize a point [x, y, z] into a unique string key
    const serializePoint = (p) => p.join(',');

    // Helper function to deserialize a string key back to a point array
    const deserializePoint = (s) => s.split(',').map(Number);

    // Set to store all unique points discovered so far (serialized strings)
    let allPointsSet = new Set();

    // 1. Check Level 0 (k=0)
    for (const p of points) {
        const s = serializePoint(p);
        allPointsSet.add(s);
        if (p.every((val, i) => val === target[i])) {
            return 0;
        }
    }

    // If only one initial point exists, no new points can ever be generated.
    if (points.length < 2) {
        return -1;
    }

    // Iteratively generate subsequent generations (k >= 1)
    let k = 0;
    let newPointsGenerated = true;

    while (newPointsGenerated) {
        k++;
        newPointsGenerated = false;

        // Convert the set of all known points into an array for easy iteration
        let currentPointsArray = Array.from(allPointsSet).map(deserializePoint);
        let nextGenerationPointsSet = new Set();

        // Generate all new points by pairing distinct points from the cumulative set
        const N = currentPointsArray.length;
        for (let i = 0; i < N; i++) {
            for (let j = i + 1; j < N; j++) {
                const p1 = currentPointsArray[i];
                const p2 = currentPointsArray[j];

                // Calculate the average point c = [floor((x1 + x2)/2), ...]
                const c = [
                    Math.floor((p1[0] + p2[0]) / 2),
                    Math.floor((p1[1] + p2[1]) / 2),
                    Math.floor((p1[2] + p2[2]) / 2)
                ];

                const cKey = serializePoint(c);

                // Check if this generated point is the target
                if (c.every((val, i) => val === target[i])) {
                    return k;
                }

                // Only add to the set if it is genuinely new to the entire collection
                if (!allPointsSet.has(cKey)) {
                    nextGenerationPointsSet.add(cKey);
                }
            }
        }

        if (nextGenerationPointsSet.size > 0) {
            newPointsGenerated = true;
            // Add all newly generated, unique points to the master set
            for (const newKey of nextGenerationPointsSet) {
                allPointsSet.add(newKey);
            }
        }
    }

    // If the loop finishes without finding the target
    return -1;
};

